import { resolvePeer } from "../users/resolve-peer.js";
async function saveDraft(client, chatId, draft) {
  const peer = await resolvePeer(client, chatId);
  if (draft) {
    await client.call({
      _: "messages.saveDraft",
      peer,
      ...draft
    });
  } else {
    await client.call({
      _: "messages.saveDraft",
      peer,
      message: ""
    });
  }
}
export {
  saveDraft
};
